function updateBrandLogoPreview(url) {
  const img = document.getElementById('brandLogoPreview');
  if (!img) return;
  if (url && url.trim() !== '') {
    img.src = url.trim();
    img.style.display = 'block';
  } else {
    img.style.display = 'none';
  }
}

function saveBrand() {
  const fields = {
    app_name:        document.getElementById('brandName'),
    app_tagline:     document.getElementById('brandTagline'),
    app_description: document.getElementById('brandDesc'),
    public_entry_mode: document.getElementById('brandPublicEntryMode'),
    contact_phone:   document.getElementById('brandPhone'),
    contact_address: document.getElementById('brandAddress'),
    contact_map_url: document.getElementById('brandMapUrl'),
    social_tg:       document.getElementById('brandTg'),
    social_vk:       document.getElementById('brandVk'),
    google_review_url: document.getElementById('brandGoogleReviewUrl'),
    logo_url:        document.getElementById('brandLogoUrl'),
    favicon_url:     document.getElementById('brandFaviconUrl'),
  };
  const brand = {};
  for (const [key, el] of Object.entries(fields)) {
    if (el) brand[key] = el.value;
  }
  const customDomainEl = document.getElementById('brandCustomDomain');
  if (customDomainEl) brand['custom_domain'] = customDomainEl.value;
  const hideBrandingEl = document.getElementById('brandHideBranding');
  if (hideBrandingEl) brand['hide_labus_branding'] = hideBrandingEl.checked ? 'true' : 'false';
  const statusEl = document.getElementById('brandStatus');
  const btn = document.getElementById('saveBrandBtn');
  const addressValue = (brand.contact_address || '').trim();
  const mapUrlValue = (brand.contact_map_url || '').trim();
  const publicEntryMode = (brand.public_entry_mode || '').trim();
  if (addressValue && /^https?:\/\//i.test(addressValue)) {
    if (statusEl) statusEl.textContent = '✗ Адрес должен быть текстом. Ссылку на карту сохраните отдельно.';
    return;
  }
  if (mapUrlValue) {
    try {
      new URL(mapUrlValue);
    } catch (error) {
      if (statusEl) statusEl.textContent = '✗ Ссылка на карту должна быть валидным URL.';
      return;
    }
  }
  if (publicEntryMode && !['homepage', 'menu'].includes(publicEntryMode)) {
    if (statusEl) statusEl.textContent = '✗ Некорректный режим публичного входа.';
    return;
  }
  if (btn) btn.disabled = true;
  if (statusEl) statusEl.textContent = 'Сохраняю...';
  const csrf = document.querySelector('meta[name="csrf-token"]')?.content
    || document.querySelector('input[name="csrf_token"]')?.value || '';
  fetch('/api/save/brand.php', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-CSRF-Token': csrf },
    body: JSON.stringify({ brand, csrf_token: csrf }),
  })
    .then((r) => r.json())
    .then((data) => {
      if (data.success && data.brand) {
        const addressEl = document.getElementById('brandAddress');
        const mapUrlEl = document.getElementById('brandMapUrl');
        const publicEntryEl = document.getElementById('brandPublicEntryMode');
        if (addressEl && typeof data.brand.contact_address === 'string') addressEl.value = data.brand.contact_address;
        if (mapUrlEl && typeof data.brand.contact_map_url === 'string') mapUrlEl.value = data.brand.contact_map_url;
        if (publicEntryEl && typeof data.brand.public_entry_mode === 'string') publicEntryEl.value = data.brand.public_entry_mode;
      }
      if (statusEl) {
        const warnings = Array.isArray(data.warnings) && data.warnings.length
          ? ` (${data.warnings.join('; ')})`
          : '';
        statusEl.textContent = data.success
          ? `✓ Сохранено${warnings}`
          : '✗ ' + (data.error || 'Ошибка');
      }
    })
    .catch(() => { if (statusEl) statusEl.textContent = '✗ Ошибка сети'; })
    .finally(() => { if (btn) btn.disabled = false; });
}

